package com.trademaster.ims.mobile.offers.controller;
import com.trademaster.ims.mobile.common.response.*;import com.trademaster.ims.mobile.offers.dto.OfferDtos.*;import com.trademaster.ims.mobile.offers.service.MobileOfferService;import jakarta.servlet.http.HttpServletRequest;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/mobile/v1/offers") public class MobileOfferController{private final MobileOfferService service;public MobileOfferController(MobileOfferService service){this.service=service;}@GetMapping public MobileApiResponse<List<OfferSummary>>list(HttpServletRequest req){return MobileApiResponse.success(service.list(req));}@GetMapping("/{id}") public MobileApiResponse<OfferDetail>detail(@PathVariable long id,HttpServletRequest req){return MobileApiResponse.success(service.detail(id,req));}@GetMapping("/{id}/products") public MobileApiResponse<OfferProductPage>products(@PathVariable long id,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size,HttpServletRequest req){return MobileApiResponse.success(service.products(id,page,size,req));}}